Here's a C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:

```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <sstream>

int main() {
    std::string filename, searchWord, word;
    int count = 0;

    // Ask user for the file name and the word to search for
    std::cout << "Enter the file name: ";
    std::cin >> filename;
    std::cout << "Enter the word to search for: ";
    std::cin >> searchWord;

    // Open the input file
    std::ifstream inputFile(filename);

    // Check if the file is open, otherwise display an error message and exit
    if (!inputFile.is_open()) {
        std::cerr << "Error opening file: " << filename << std::endl;
        return 1;
    }

    // Read the file line by line
    while (std::getline(inputFile, word)) {
        // Create a stringstream to break the line into words
        std::istringstream lineStream(word);

        // Iterate through the words in the line
        while (lineStream >> word) {
            // Convert both words to lowercase for case-insensitive comparison
            std::transform(word.begin(), word.end(), word.begin(), ::tolower);
            std::transform(searchWord.begin(), searchWord.end(), searchWord.begin(), ::tolower);

            // If the current word matches the search word, increment the counter
            if (word == searchWord) {
                count++;
            }
        }
    }

    // Close the input file
    inputFile.close();

    // Output the result
    std::cout << "The word '" << searchWord << "' occurs " << count << " times in the file." << std::endl;

    return 0;
}
```

